svg.script:
var lines = [
  "Turning data into decisions \uD83D\uDCCA",
  "\u25811\u25812\u25814\u25816\u25816\u25814\u25812\u25811  crunching numbers daily",
  "A |\u2588\u2588\u2588\u2588\u2588\u2588\u2588\u2588\u2591\u2591| 62% \u2190 found the winner \u2713",
  "B |\u2588\u2588\u2588\u2588\u2588\u2588\u2588\u2588\u2588\u2588| 78% \u2713",
  "retention \uD83D\uDCC9 0.35% \u2192 found why \uD83D\uDD0D",
  "\u2588\u2588\u2588\u2588\u2588 visitors \u2192 \u2588\u2588 retained \u2192 \uD83D\uDCA1 insights"
];
var el = document.getElementById('txt');
var cur = document.getElementById('cur');
var li = 0, ci = 0, del = false;
function upd() {
  var bb = el.getBBox();
  cur.setAttribute('x', bb.x + bb.width + 3);
}
function run() {
  var line = lines[li];
  if (!del) {
    if (ci <= line.length) {
      el.textContent = line.slice(0, ci++);
      upd();
      setTimeout(run, ci === line.length ? 2000 : 60);
    } else { del = true; setTimeout(run, 80); }
  } else {
    if (ci > 0) {
      el.textContent = line.slice(0, --ci);
      upd();
      setTimeout(run, 35);
    } else {
      del = false;
      li = (li + 1) % lines.length;
      setTimeout(run, 400);
    }
  }
}
run();
